import "./index.css";
import usefetch from './fetchdata.js'; // your custom hook
import { Link } from 'react-router-dom';

const Homepage = () => {
  const tasks = usefetch() || []; // fetch tasks

  if (!tasks) return <p>Loading tasks...</p>;

  return (
    <div className="homepage">
      {/* To Do Tasks */}
      <div className="yts">
        <h5>To Do Task's</h5>
        {tasks
          .filter((task) => task.status === "todIn progress")
          .map((task) => (
            <div className="status" key={task.id}>
              <p>{task.name}</p>
            </div>
          ))}
      </div>

      {/* In Progress */}
      <div className="inprogress">
        <h5>In Progress</h5>
        {tasks
          .filter((task) => task.status === "inprogress")
          .map((task) => (
            <div className="status" key={task.id}>
              <p>{task.name}</p>
            </div>
          ))}
      </div>

      {/* Completed */}
      <div className="Completed">
        <h5>Completed</h5>
        {tasks
          .filter((task) => task.status === "completed")
          .map((task) => (
            <div className="status" key={task.id}>
              <p>{task.name}</p>
            </div>
          ))}
      </div>
    </div>
  );
};

export default Homepage;
